__kernel void compute_distances(
    __global const char* sandbox,
    const int rec_length,
    const int latitude_pos,
    const int rec_count,
    const float target_lat,
    const float target_long,
    __global float* z)
{
    int i = get_global_id(0);
    if(i < rec_count) {
        int base_idx = i * rec_length + latitude_pos - 1;

        // Copy latitude string safely (max 7 chars + null terminator)
        char lat_str[8];
        int lat_len = 0;
        for(int c = 0; c < 7; c++) {
            char ch = sandbox[base_idx + c];
            lat_str[c] = ch;
            if(ch == ' ' || ch == '\0' || ch == '\n') {
                lat_len = c;
                break;
            }
            lat_len = c + 1;
        }
        lat_str[lat_len] = '\0';

        // Copy longitude string safely (max 7 chars + null terminator)
        char long_str[8];
        int long_len = 0;
        int long_start = base_idx + 7;
        for(int c = 0; c < 7; c++) {
            char ch = sandbox[long_start + c];
            long_str[c] = ch;
            if(ch == ' ' || ch == '\0' || ch == '\n') {
                long_len = c;
                break;
            }
            long_len = c + 1;
        }
        long_str[long_len] = '\0';

        float tmp_lat = atof(lat_str);
        float tmp_long = atof(long_str);

        float diff_lat = tmp_lat - target_lat;
        float diff_long = tmp_long - target_long;

        z[i] = sqrt(diff_lat * diff_lat + diff_long * diff_long);
    }
}
